import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Divider } from '@mui/material';
import response from './response.json';

interface CartSummary {
  itemCount: number;
  totalPrice: number;
  totalSavings: number;
}

interface Item {
  name: string;
  price: number;
  savings: number;
}

interface CartData {
  cartSummary: CartSummary;
  items: Item[];
}

export default function Widget() {
  const cartData = response.data as CartData;
  const { cartSummary, items } = cartData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} color="primary">
              Cart Summary
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {cartSummary.itemCount} items
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1F2937', mt: 0.5 }}>
              ${cartSummary.totalPrice.toFixed(2)}
            </Typography>
            <Typography variant="body2" sx={{ color: '#FF4081' }}>
              Savings: ${cartSummary.totalSavings.toFixed(2)}
            </Typography>
          </Box>

          <Divider sx={{ my: 1 }} />

          <Stack spacing={1}>
            {items.map((item, index) => (
              <Box key={index}>
                <Stack direction="row" justifyContent="space-between" alignItems="center">
                  <Typography variant="body2" fontWeight={500}>
                    {item.name}
                  </Typography>
                  <Box textAlign="right">
                    <Typography variant="body2" sx={{ color: '#1F2937', fontWeight: 500 }}>
                      ${item.price.toFixed(2)}
                    </Typography>
                    <Typography variant="caption" sx={{ color: '#FF4081' }}>
                      -${item.savings.toFixed(2)}
                    </Typography>
                  </Box>
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
